parameters.jsCode:
// Validate + normalize the insert payload before SQL.
const raw = $input.first().json;
const body = raw.body || raw;

const menuItemId = parseInt(body.menu_item_id ?? body.menuItemId, 10);
const photoUrl = String(body.photo_url ?? body.photoUrl ?? '').trim();
const sortOrder = Number.isFinite(parseInt(body.sort_order ?? body.sortOrder, 10))
  ? parseInt(body.sort_order ?? body.sortOrder, 10) : 0;
const isVisibleRaw = body.is_visible ?? body.isVisible;
const isVisible = isVisibleRaw === false ? false : true;

if (!Number.isFinite(menuItemId) || menuItemId <= 0) {
  return [{ json: { ok: false, error: 'menu_item_id required (positive integer)' } }];
}
if (!photoUrl || !/^https?:\/\//i.test(photoUrl)) {
  return [{ json: { ok: false, error: 'photo_url required (http/https URL)' } }];
}

return [{ json: { ok: true, menu_item_id: menuItemId, photo_url: photoUrl, sort_order: sortOrder, is_visible: isVisible } }];

